parameters.jsCode:
// Source nodes
const orch = $('Parse Surname Crosser').first().json;
const obit = $('Parse Obituary Output').first().json;

// Parse Title Attorney raw agent output
const taRaw = ($input.first().json.output || '').replace(/```json\n?/g, '').replace(/```/g, '').trim();
let ta = {};
try {
  ta = JSON.parse(taRaw);
} catch(_) {
  const s = taRaw.indexOf('{');
  const e = taRaw.lastIndexOf('}');
  if (s !== -1 && e > s) {
    try { ta = JSON.parse(taRaw.slice(s, e + 1)); } catch(_) {}
  }
}

// Resolve vital status — obituary is ground truth, SkipGenie is fallback
let vital_status = 'unknown';
if (obit.is_deceased === true)             vital_status = 'deceased';
else if (obit.is_deceased === false)       vital_status = 'living';
else if (orch.skipgenie_deceased === true)  vital_status = 'deceased';
else if (orch.skipgenie_deceased === false) vital_status = 'living';

const deedCheck  = ta.deed_check  || {};
const courtCheck = ta.court_check || {};
const estFiled   = courtCheck.estate_filed !== undefined ? courtCheck.estate_filed : null;
const hadWill    = courtCheck.had_will     !== undefined ? courtCheck.had_will     : null;

const cascade_needed = vital_status === 'deceased' && estFiled !== true;
const identity = orch.matched_identity || {};

// ---------------------------------------------------------------------------
// Build cascade_relatives — merge all genealogical sources
// Priority: obituary survivors (confirmed obit) > ancestry children > skipgenie
// ---------------------------------------------------------------------------

function normName(n) {
  return (n || '').toUpperCase().replace(/[^A-Z ]/g, '').trim().replace(/\s+/g, ' ');
}

const JUNK = [/^HEIRS OF/i, /^HEIR OF/i, /^ESTATE OF/i, /^ESTATE$/i,
              /^UNKNOWN$/i, /^N\/A$/i, /^NA$/i, /^NONE$/i, /^NULL$/i];
function isJunk(name) {
  if (!name || name.trim().length < 3) return true;
  if (/^\d+$/.test(name.trim())) return true;
  return JUNK.some(p => p.test(name.trim()));
}

const seen = new Set();
const cascade_relatives = [];

function addRelative(name, relationship, source) {
  if (isJunk(name)) return;
  const key = normName(name);
  if (!key || seen.has(key)) return;
  seen.add(key);
  const item = { name: name.trim(), relationship: relationship || 'unknown', source };
  cascade_relatives.push(item);
  return item;
}

// 1. Obituary survivors — ONLY when obit was accepted (confidence high or medium)
const obitConfidence = obit.confidence || obit.obit_confidence || '';
if (obitConfidence === 'high' || obitConfidence === 'medium') {
  for (const s of (obit.survivors || [])) {
    if (typeof s === 'string') {
      addRelative(s, 'survivor', 'obituary');
    } else if (s && s.name) {
      const rel = addRelative(s.name, s.relationship || 'survivor', 'obituary');
      if (rel && s.maiden_name) rel.maiden_name = s.maiden_name;
    }
  }
}

// 2. Ancestry children — agent already filtered by relevance
for (const c of (obit.ancestry_children || [])) {
  if (typeof c === 'string') {
    addRelative(c, 'child', 'ancestry');
  } else if (c && c.name) {
    addRelative(c.name, c.relationship || 'child', 'ancestry');
  }
}

// 3. SkipGenie possible_relatives — fill remaining gaps only
for (const r of (orch.cascade_relatives || [])) {
  if (typeof r === 'string') {
    addRelative(r, 'unknown', 'skipgenie');
  } else if (r && r.name) {
    addRelative(r.name, r.relationship || 'unknown', 'skipgenie');
  }
}

return [{ json: {
  name:              orch.name || '',
  property_id:       orch.property_id,
  session_id:        orch.session_id,
  queue_id:          orch.queue_id,
  loop_context:      orch.loop_context || 'worker',
  relationship_hint: orch.relationship_hint || '',
  age:               orch.age || '',
  phone:             orch.phone || '',
  address:           orch.address || '',
  county:            orch.county || '',
  parcel_id:         orch.parcel_id || '',
  matched_identity:  identity,
  cascade_relatives,
  vital_status,
  deceased_facts: {
    date_of_death:           obit.date_of_death           || '',
    marital_status_at_death: obit.marital_status_at_death || '',
    surviving_spouse_name:   obit.surviving_spouse        || '',
    estate_filed:            estFiled,
    had_will:                hadWill,
    family_alive_at_death:   obit.survivors               || [],
  },
  deed_transfers:  deedCheck.transfers || [],
  cascade_needed,
  obituary_url:    obit.obituary_url  || '',
  obituary_text:   obit.obituary_text || '',
  claim_sources: {
    date_of_death: {
      value:      obit.date_of_death || '',
      source:     obit.obituary_url ? 'obituary' : (identity.dod ? 'skipgenie' : 'unknown'),
      url:        obit.obituary_url || '',
      confidence: obit.date_of_death ? (obit.confidence || 'medium') : 'none',
    },
    marital_status_at_death: {
      value:      obit.marital_status_at_death || '',
      source:     obit.marital_status_at_death ? 'obituary' : 'unknown',
      confidence: obit.marital_status_at_death ? 'medium' : 'none',
    },
    estate_filed: {
      value:        estFiled,
      source:       estFiled !== null ? 'nc_courts' : 'unknown',
      case_numbers: (courtCheck.cases || []).map(c => c.case_number).filter(Boolean),
      confidence:   estFiled !== null ? 'high' : 'low',
    },
    had_will: {
      value:      hadWill,
      source:     hadWill !== null ? 'register_of_actions' : 'unknown',
      confidence: hadWill !== null ? 'medium' : 'none',
    },
    family_alive_at_death: {
      sources:    (obit.survivors || []).length ? ['obituary'] : [],
      confidence: (obit.survivors || []).length ? (obitConfidence || 'medium') : 'none',
    },
  },
  maiden_name:        obit.maiden_name || '',
  skipgenie_deceased: orch.skipgenie_deceased,
  notes: [orch.notes ? 'Orch: ' + orch.notes : '', ta.notes ? 'TA: ' + ta.notes : ''].filter(Boolean).join(' | '),
} }];

parameters.jsonBody:
={{ (function() {
  const pc = $('Person Compiler').first().json;
  if (!pc.cascade_needed) {
    return { session_id: pc.session_id, property_id: pc.property_id, persons: [] };
  }
  const INVALID = ['HEIRS OF','HEIR OF','ESTATE OF','UNKNOWN','CHILDREN OF','DESCENDANTS OF'];
  function isValidName(name) {
    if (!name || name.length < 3) return false;
    const u = name.toUpperCase();
    if (INVALID.some(p => u.startsWith(p))) return false;
    if (name.split(' ').filter(Boolean).length < 2) return false;
    return true;
  }
  return {
    session_id: pc.session_id,
    property_id: pc.property_id,
    persons: (pc.cascade_relatives || [])
      .map(r => ({
        name: (r.name || '').replace(/\s*\(.*?\)/g, '').trim(),
        relationship_hint: (r.relationship || 'cascade_heir').substring(0, 120)
      }))
      .filter(r => isValidName(r.name))
  };
})() }}

